(1, 'PRAYER MINISTRY', 'Alpara', 'Trissuur', '', 680542, 'Pazhanji', 'Thrissur', 'Kerala', 'India', '6238739612', '6238983871', 'prayerministryl@gmail.com', '', '', 'JeahTech', NULL, 1, '2022-08-12 18:44:26', '2021-12-31 18:30:00');
INSERT INTO `header_data` (`id`, `lang_id`, `praise`, `title`, `details`, `verses`, `status`, `created_at`, `updated_at`) VALUES
(1, 1, 'Praise The Lord', 'THE PENTECOSTAL MISSION, PRAYER MINISTRY', 'Praise & Pray', 'Therefore, my beloved brethren, be ye steadfast, unmovable, always abounding in the work of the Lord,  forasmuch as ye know that your labor is not in vain in the Lord. (1Cor. 15:58)', 1, '2022-08-15 17:44:57', '2022-08-15 17:44:57'),
(2, 2, 'ദൈവത്തിന് മഹത്വം', 'ദി പെന്തെക്കൊസ്തു മിഷന്‍, പ്രാര്‍ത്ഥനാ ശുശ്രൂഷ', 'പ്രാര്‍ത്ഥനക്കും, സ്തോത്രത്തിനും', 'ആകയാല്‍ എന്‍റെ പ്രിയ സഹോദരന്മാരേ, നിങ്ങള്‍ ഉറപ്പുള്ളവരും കുലുങ്ങാത്തവരും നിങ്ങളുടെ പ്രയത്നം കര്‍ത്താവില്‍ വ്യര്‍ത്ഥമല്ല എന്നു അറിഞ്ഞിരിക്കയാല്‍ കര്‍ത്താവിന്‍റെ വേലയില്‍ എപ്പോഴും വര്‍ദ്ധിച്ചുവരുന്നവരും ആകുവിന്‍. (1കൊരി. 15:58)', 1, '2022-08-15 17:52:02', '2022-08-15 17:52:02'),
(4, 3, 'தேவனுக்குமகிமை', 'தி டிபந்தெகொழூ;தெ சபை டிகூபஊர்pயம்', 'ஜெபத்திற்கும் ஸ்தோத்திரத்திற்கும்', 'ஆகையால் எனக்குப் பிரியமான சகோதரரே, கர்த்தருக்குள் நீங்கள் படுகிற பிரயாசம் விருதாவாயிராதென்று அறிந்து,  நீங்கள் உறுதிப்பட்டவர்களாயும்,  அசையாதவர்களாயும், கர்த்தருடைய கிரியையிலே எப்பொழுதும் பெருகுகிறவர்களாயும் இருப்பீர்களாக ( ஐ கொரி.15:58 )', 1, '2022-08-16 09:29:01', '2022-08-16 09:29:01');
