INSERT INTO `terms` (`id`, `lang_id`, `title`, `terms`, `status`, `created_at`, `updated_at`) VALUES
(1, 1, 'Be careful while praying', '<ol><li><span style=\"font-size: 18px;\">Mathew 26 :40, Choose a favorable time to pray one hour on a daily basis on the same time everyday out of the 24 hours given by God. Failed to do so, spare an appropriate time to compensate the prayer on the same day. Continue the prayer even if a day skipped.&nbsp;</span></li><li><span style=\"font-size: 18px;\">John 9:31 In order to have our prayer, we should confess our sins and scarify us and we have to pray.&nbsp;</span></li><li><span style=\"font-size: 18px;\">Philippians 4: 6-7 To pray for others peacefully, in everything with thanks giving let you requests be made known unto God.&nbsp;</span></li><li><span style=\"font-size: 18px;\">Job 42:10 To be blessed twice we must praise for them that on in the prayer chain list by thanks giving unto God. (Take not more than&nbsp; half 20 minutes for the above 3 points.)&nbsp;</span></li><li><span style=\"font-size: 18px;\">John 16: 24 That your joy may be full, then given prayer topics are to be taken one by one&nbsp; accordingly (Jacob 5:16) pray fervently for each other and every points in the list</span></li><li><span style=\"font-size: 18px;\">1 Samuel 12:23 Once in a week, Pray willingly for the people, by names, Who are in the prayer chain list.&nbsp;</span></li><li><span style=\"font-size: 18px;\">1 Corinthians 10:24 If you are interested in these prayer arrangements let others also know so that it would be a help for other prayer livers.</span></li></ol>', 1, '2022-08-14 13:10:08', '2022-08-14 13:10:08'),
(2, 2, 'പ്രാര്‍ത്ഥിക്കുമ്പോള്‍ ശ്രദ്ധിക്കുക', '<ol><li><span style=\"font-size: 17px;\">മത്തായി 26:40 ദൈവം നമുക്ക് തന്നിരിക്കുന്ന 24 മണിക്കൂറില്‍ സൗകര്യമായ ഒരു മണിക്കൂര്‍ സമയം തിരഞ്ഞെടുത്ത് ദിവസവും ആ സമയത്തുതന്നെ കഴിവതും പ്രാര്‍ത്ഥിക്കുക. ആ സമയത്ത് സാധിച്ചില്ലായെങ്കില്‍ മറ്റൊരു സമയം അന്നുതന്നെ കണ്ടെത്തി പ്രാര്‍ത്ഥിക്കുക. ഒരു ദിവസം മുടങ്ങിയാലും തുടര്‍ന്ന് പ്രാര്‍ത്ഥിക്കുക.</span></li><li><span style=\"font-size: 17px;\">യോഹന്നാന്‍ 9 : 31 ദൈവം പ്രാര്‍ത്ഥന കേള്‍ക്കേണ്ടതിന് പാപങ്ങളെ ഏറ്റുപറഞ്ഞ് നമ്മെതന്നെ ശുദ്ധീകരിച്ച് പ്രാര്‍ത്ഥിക്കുക.</span></li><li><span style=\"font-size: 17px;\">ഫിലിപ്പിയര്‍ 4:6-7 നാം മറ്റുള്ളവര്‍ക്കുവേണ്ടി സമാധാനത്തോടെ പ്രാര്‍ത്ഥിക്കേണ്ടുന്നവരാകയാല്‍ നമ്മുടെ ആവശ്യങ്ങളൊക്കേയും സ്തോത്രത്തോടെ ദൈവത്തോട് അറിയിച്ച് പ്രാര്‍ത്ഥിക്കുക.</span></li><li><span style=\"font-size: 17px;\">1 തെസ്സെലോനിക്ക്യര്‍ 5 : 18&nbsp; പ്രാര്‍ത്ഥനാ സഹകാരികളുടെ പേരു പറഞ്ഞ് അവര്‍ക്കായി ദിവസവും സ്തോത്രം ചെയ്യുക. (ഈ 2, 3 4 കാര്യങ്ങള്‍ക്കായി 20 മിനിറ്റില്‍ താഴെ മാത്രം എടുക്കുക.)</span></li><li><span style=\"font-size: 17px;\">യോഹന്നാന്‍ 16:24 നമ്മുടെ സന്തോഷം പൂര്‍ണ്ണമാക തക്കവണ്ണം കൊടുക്കപ്പെട്ട പ്രാര്‍ത്ഥനാ വിഷയങ്ങള്‍ ഓരോ ലിസ്റ്റ് വീതം മാറിമാറിയെടുത്ത് ഓരോ ലിസ്റ്റിലേയും ഓരോ വിഷയങ്ങളും പറഞ്ഞ് (യാക്കോബ് 5:16) ശ്രദ്ധയോടുകൂടി പ്രാര്‍ത്ഥിക്കുക.</span></li><li><span style=\"font-size: 17px;\">ഇയ്യോബ് 42:10 നാം ഇരട്ടിയായി അനുഗ്രഹിക്കപ്പെടേണ്ടതിന് (1ശമുവേല്‍ 12:23) ആഴ്ചയിലോരിക്കല്‍ പ്രാര്‍ത്ഥനാ സഹകാരികളുടെ പേരു പറഞ്ഞ് അവര്‍ക്കായി താല്‍പ്പര്യത്തോടെ പ്രാര്‍ത്ഥിക്കുക.</span></li><li><span style=\"font-size: 17px;\">1 കൊരിന്ത്യര്‍ 10:24 ഈ പ്രാര്‍ത്ഥനാ ക്രമീകരണം നിങ്ങള്‍ക്ക് സന്തോഷമെങ്കില്‍ മറ്റുള്ളവരുടെ പ്രാര്‍ത്ഥനാ ജീവിതത്തിനു സഹായികളായി അവരോടും ഇത് അറിയിക്കുക.</span></li></ol>', 1, '2022-08-14 13:30:15', '2022-08-14 13:30:15'),
(3, 3, 'ஜெபிக்கும்போது கவனிக்கவும்', '<ol><li><b><span style=\"font-size: 16px;\">(மத்தேயு 26:40)&nbsp; தேவன் நமக்கு தந்திருக்கிற 24 மணி நேரத்தில் வசதியான ஒரு மணிநேரம் தெரிந்தெடுத்து தினமும் அந்த நேரத்திலேயே ஜெபிக்கவும் அந்த நேரத்தில் ஜெபிக்க முடியாவிட்டால்&nbsp; அந்த நாளிலேயே மற்றொரு நேரத்தில் ஜெபிக்கவும் ஒரு நாளில் ஜெபம் தடைபட்டாலும் மறுநாளிலிருந்து தொடர்ந்து ஜெபிக்கவும்</span></b></li><li><b><span style=\"font-size: 16px;\">(யோவான் 9:31) தேவன் நம்முடைய ஜெபத்தைக் கேட்பதற்காக நம்மை நாமே சுத்திகரித்து ஜெபிக்க வேண்டும்</span></b></li><li><b><span style=\"font-size: 16px;\">(பிலிப்பியர் 4:6,7) சமாதானமுள்ளவர்களாக ஜெபிப்பதற்கு நம்முடைய தேவைகள் எல்லாவற்றையும் ஸ்தோத்திரத்துடன் தேவனிடம் அறிவித்து ஜெபிக்க வேண்டும்.</span></b></li><li><b><span style=\"font-size: 16px;\">(யோபு 42:10) நாம் இரட்டிப்பான ஆசீர்வாதங்களைப் பெற்றுக்கொள்ள ஜெப குழுவில் உள்ளவர்களுடைய பெயர் சொல்லி அவர்களுக்காக தினமும் ஸ்தோத்திரம் செய்யவும் வாரத்தில் ஒரு முறை ஜெபிக்கவும் வேண்டும்.</span></b></li><li><b><span style=\"font-size: 16px;\">(யோவான் 16:24)&nbsp; நம்முடைய சந்தோ~ம் நிறைவாயிருக்கும்படி கொடுக்கப்பட்ட ஜெப காரியங்களை (யாக்கோபு 5:16) ன் படி ஊக்கமாக ஜெபிக்கவும் வேண்டும்.</span></b></li><li><b><span style=\"font-size: 16px;\">(1 சாமுவேல்12:23) ஜெப குழுவில் உள்ளவர்களுடைய பெயர் சொல்லி அவர்களுக்காக வாரத்தில் ஒரு முறை மனப்பூர்வமாக ஜெபிக்க வேண்டும்.</span></b></li><li><b><span style=\"font-size: 16px;\">(1 கொரிந்தியர் 10:24) இந்த ஜெப ஒழுங்கு உங்களுக்கு சந்தோ~மாயிருந்தால் (உதவி) மற்றவர்களுடைய ஜெப வாழ்க்கைக்கும் உதவியாயிருக்கும் படி அறிவிக்கவும்.</span></b></li></ol>', 1, '2022-08-14 13:36:04', '2022-08-14 13:36:04');
